'use strict';
flow.set('ma_config', msg.payload);
// ─── Shared OSC broadcast helper (stored once; retrieved by command nodes) ────
var dgram = require('dgram');
function oscString(str) {
    var len = Buffer.byteLength(str, 'utf8') + 1;
    var padded = Math.ceil(len / 4) * 4;
    var buf = Buffer.alloc(padded, 0);
    buf.write(str, 0, 'utf8');
    return buf;
}
function encodeOscCmd(v) {
    return Buffer.concat([oscString('/cmd'), oscString(',s'), oscString(v)]);
}
function maOscBroadcast(cmdString, targets) {
    return new Promise(function(resolve, reject) {
        var buf = encodeOscCmd(cmdString);
        var socket = dgram.createSocket('udp4');
        if (socket.unref) socket.unref();
        var sent = [], errors = [];
        var remaining = targets.length;
        socket.on('error', function(sockErr) {
            try { socket.close(); } catch (e) {}
            reject(sockErr);
        });
        if (remaining === 0) {
            try { socket.close(); } catch (e) {}
            resolve({ cmdString: cmdString, sent: sent, errors: errors });
            return;
        }
        var finish = function() {
            try {
                socket.close(function() {
                    if (errors.length === targets.length) reject(new Error(errors.join('; ')));
                    else resolve({ cmdString: cmdString, sent: sent, errors: errors });
                });
            } catch (e) {
                if (errors.length === targets.length) reject(new Error(errors.join('; ')));
                else resolve({ cmdString: cmdString, sent: sent, errors: errors });
            }
        };
        targets.forEach(function(t) {
            socket.send(buf, 0, buf.length, t.port, t.host, function(err) {
                if (err) errors.push(t.host + ':' + t.port + ' - ' + err.message);
                else sent.push(t.host + ':' + t.port);
                if (--remaining === 0) finish();
            });
        });
    });
}
flow.set('ma_broadcast', maOscBroadcast);
return null;

